// Build both the plain-text summary AND the Block Kit card payload.
// Defensive: the Extractor returns arrays as JSON-encoded strings sometimes,
// or comma-separated strings when its parsing fell back. Handle both.

const toArray = (v) => {
  if (Array.isArray(v)) return v;
  if (v == null) return [];
  if (typeof v === 'string') {
    const s = v.trim();
    if (!s) return [];
    // Try JSON first
    if (s.startsWith('[')) {
      try { return JSON.parse(s); } catch (e) { /* fall through */ }
    }
    // Fall back to comma split for simple string lists
    return s.split(',').map(x => x.trim()).filter(Boolean);
  }
  return [v];
};

const data = $input.first().json.data || {};
const trig = $('Watch Channel for Messages').first().json;
const meta = {
  file_name: trig.files?.[0]?.name,
  user_id: trig.user,
  channel: trig.channel,
  thread_ts: trig.ts
};

const name = data.full_name || 'Unknown candidate';
const location = data.location || null;
const yoe = data.total_years_experience;
const skills = toArray(data.top_skills);
const roles = toArray(data.last_three_roles);
const education = toArray(data.education);
const salary = data.salary_expectations || null;
const linkedin = data.linkedin_url || null;

// --- Plain text summary (for the first message) ---
const lines = [`*${name}*`];
if (location) lines.push(`📍 ${location}`);
if (yoe != null) lines.push(`💼 ${yoe} year${yoe === 1 ? '' : 's'} experience`);
if (skills.length) lines.push(`🛠 ${skills.join(' • ')}`);
if (roles.length) {
  lines.push('');
  lines.push('*Recent roles*');
  for (const r of roles) {
    const period = r.end ? `${r.start || '?'} – ${r.end}` : (r.start || '');
    lines.push(`• ${r.title || '?'} @ ${r.company || '?'}${period ? `  _(${period})_` : ''}`);
  }
}
if (education.length) {
  lines.push('');
  lines.push('*Education*');
  for (const e of education) {
    lines.push(`• ${e.degree || '?'}${e.institution ? ` — ${e.institution}` : ''}${e.year ? ` (${e.year})` : ''}`);
  }
}
if (salary) lines.push(`\n💰 Salary expectations: ${salary}`);
if (linkedin) lines.push(`🔗 ${linkedin}`);

const summaryText = lines.join('\n');

// --- Block Kit card (second message, with action buttons) ---
// Carries the extracted data in the button's value field so Workflow B
// can append to Sheet without re-running the Extractor.
const payload = {
  candidate_name: name,
  location,
  total_years_experience: yoe,
  top_skills: skills,
  last_three_roles: roles,
  education,
  salary_expectations: salary,
  linkedin_url: linkedin,
  file_name: meta.file_name,
  source_user: meta.user_id,
  source_channel: meta.channel,
  source_thread: meta.thread_ts
};

// Slack action value has a 2000 char limit. JSON of typical CV fits easily,
// but truncate roles/education descriptions just in case.
const valueStr = JSON.stringify(payload);
if (valueStr.length > 1900) {
  // Rare, but fail loud rather than silently corrupting the button payload.
  throw new Error(`Block Kit action value too large: ${valueStr.length} chars`);
}

const card = {
  blocks: [
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `What do you want to do with *${name}*?` }
    },
    {
      type: 'actions',
      block_id: 'cv_actions',
      elements: [
        {
          type: 'button',
          action_id: 'save_to_sheet',
          style: 'primary',
          text: { type: 'plain_text', text: '💾 Save to Sheet' },
          value: valueStr
        },
        {
          type: 'button',
          action_id: 'dismiss',
          text: { type: 'plain_text', text: 'Dismiss' },
          value: 'dismiss'
        }
      ]
    }
  ]
};

return [{
  json: {
    summary_text: summaryText,
    card_blocks: card.blocks,
    channel: meta.channel,
    thread_ts: meta.thread_ts
  }
}];
